/* --- Helper function Master (Luna) --- */
static void render_luna_master(void) {
    int wpm = get_current_wpm();
    int frame = (timer_read() / ANIM_FRAME_DURATION) % 2;

    // Luna bottom left (Cursor 0, 13)
    oled_set_cursor(0, 13);
    if (wpm <= 10) oled_write_raw_P(sit[frame], LUNA_SIZE);
    else if (wpm <= 40) oled_write_raw_P(walk[frame], LUNA_SIZE);
    else oled_write_raw_P(run[frame], LUNA_SIZE);
}

static void print_status_master(void) {
    // USB Status for lock entries
    led_t led_usb_state = host_keyboard_led_state();

    // Layer display
    oled_set_cursor(0, 2);
    oled_write("LAYER", false);
    oled_set_cursor(0, 3);
    switch (get_highest_layer(layer_state)) {
        case 0: oled_write("Base ", false); break;
        case 1: oled_write("Raise", false); break;
        case 2: oled_write(" Num ", false); break;
        case 3: oled_write("Ambi ", false); break;
        case 4: oled_write("Game ", false); break;
    }

    // Lock Displays
    oled_set_cursor(0, 6);
    oled_write("LOCK", false);

    oled_set_cursor(0, 7);
    oled_write("Caps", led_usb_state.caps_lock);

    oled_set_cursor(0, 8);
    oled_write("Num ", led_usb_state.num_lock);

    oled_set_cursor(0, 9);
    oled_write("Scrl", led_usb_state.scroll_lock);

    render_luna_master();
}

/* --- Helper function for Slave (Bongo) --- */
static void render_bongo_slave(void) {
    int wpm = get_current_wpm();
    int frame = (timer_read() / ANIM_FRAME_DURATION) % 2;

    oled_set_cursor(0, 1);
    if (wpm <= 30) {
        oled_write_raw_P(bongo_idle[0], BONGO_SIZE);
    } else {
        oled_write_raw_P(bongo_tap[frame], BONGO_SIZE);
    }
}

static void print_status_slave(void) {
    render_bongo_slave();

    // WPM Counter unten
    char wpm_str[10];
    oled_set_cursor(0, 13);
    sprintf(wpm_str, " %03d\n WPM", get_current_wpm());
    oled_write(wpm_str, false);
}

/* --- Main function --- */
oled_rotation_t oled_init_user(oled_rotation_t rotation) {
    return OLED_ROTATION_270;
}

bool oled_task_user(void) {
    if (is_keyboard_master()) {
        print_status_master();
    } else {
        print_status_slave();
    }
    return false;
}

